"""A readable parser for standard 5-field cron expressions.

The public entry point is `parse_cron`, which turns a string such as
"0 12 * * 1-5" into a `CronSchedule`. The schedule exposes the expanded values
for every field and a `describe()` method that renders a human-readable summary.

The design separates three concerns so each can be read on its own:

1. Parsing one field into its set of values (`parse_field`).
2. Holding the parsed result as structured data (`CronField`, `CronSchedule`).
3. Turning that structure into English (the `describe` helpers).
"""

from __future__ import annotations

import re
from dataclasses import dataclass


# --------------------------------------------------------------------------- #
# Errors and field definitions
# --------------------------------------------------------------------------- #


class CronParseError(ValueError):
    """Raised when a cron expression cannot be parsed or is out of range."""


@dataclass(frozen=True)
class FieldSpec:
    """The name and valid value range for a single cron field."""

    name: str
    min_value: int
    max_value: int


# The five fields, in the order they appear in a cron expression.
MINUTE = FieldSpec("minute", 0, 59)
HOUR = FieldSpec("hour", 0, 23)
DAY_OF_MONTH = FieldSpec("day_of_month", 1, 31)
MONTH = FieldSpec("month", 1, 12)
DAY_OF_WEEK = FieldSpec("day_of_week", 0, 6)

FIELD_ORDER: tuple[FieldSpec, ...] = (
    MINUTE,
    HOUR,
    DAY_OF_MONTH,
    MONTH,
    DAY_OF_WEEK,
)

WEEKDAY_NAMES: tuple[str, ...] = (
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
)

MONTH_NAMES: tuple[str, ...] = (
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
)


# --------------------------------------------------------------------------- #
# Parsed data structures
# --------------------------------------------------------------------------- #


@dataclass(frozen=True)
class CronField:
    """A single parsed field: its original text and expanded set of values.

    The `raw` token is kept alongside the expanded `values` because it lets the
    description layer tell *how* a value set was written (a wildcard, a step, a
    range, or a list) without re-deriving that from the numbers alone.
    """

    raw: str
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        """True for `*` — the field matches every value in its range."""
        return self.raw == "*"

    @property
    def is_step(self) -> bool:
        """True for step syntax such as `*/15` or `1-30/5`."""
        return "/" in self.raw

    @property
    def step(self) -> int | None:
        """The step size, e.g. 15 for `*/15`; None when no step."""
        if not self.is_step:
            return None
        return int(self.raw.split("/", 1)[1])

    @property
    def is_single_value(self) -> bool:
        """True for a bare number such as `42`."""
        return re.fullmatch(r"\d+", self.raw) is not None

    @property
    def is_simple_range(self) -> bool:
        """True for a contiguous range such as `1-5` (no step, no list)."""
        return re.fullmatch(r"\d+-\d+", self.raw) is not None


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression with all five fields."""

    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Return a human-readable English summary of the schedule."""
        time_clause = self._describe_time()
        day_clause = self._describe_calendar()
        if day_clause:
            return f"{time_clause} {day_clause}"
        return time_clause

    # --- time of day (minute + hour) ------------------------------------- #

    def _describe_time(self) -> str:
        minute, hour = self.minute, self.hour

        if minute.is_wildcard and hour.is_wildcard:
            return "Every minute"

        if minute.is_step and hour.is_wildcard:
            return f"Every {minute.step} minutes"

        if hour.is_step and _is_on_the_hour(minute):
            return f"Every {hour.step} hours, on the hour"

        if minute.is_single_value and hour.is_single_value:
            return _describe_clock_time(hour.values[0], minute.values[0])

        return self._describe_irregular_time()

    def _describe_irregular_time(self) -> str:
        """Fallback for combinations the common cases above don't cover."""
        minutes = join_human([f"{m:02d}" for m in self.minute.values])
        if self.hour.is_wildcard:
            return f"At minute {minutes} of every hour"

        clock_times = [
            _describe_clock_time(hour, minute)
            for hour in self.hour.values
            for minute in self.minute.values
        ]
        return join_human(clock_times)

    # --- calendar (day-of-month + month + day-of-week) ------------------- #

    def _describe_calendar(self) -> str:
        clauses: list[str] = []

        if not self.day_of_month.is_wildcard:
            clauses.append(self._describe_day_of_month())

        if not self.day_of_week.is_wildcard:
            clauses.append(f"on {self._describe_weekdays()}")

        if self.day_of_month.is_wildcard and not self.month.is_wildcard:
            clauses.append(f"in {self._describe_months()}")

        return " ".join(clauses)

    def _describe_day_of_month(self) -> str:
        days = join_human([ordinal(day) for day in self.day_of_month.values])
        if self.month.is_wildcard:
            return f"on the {days} of every month"
        return f"on the {days} of {self._describe_months()}"

    def _describe_weekdays(self) -> str:
        field = self.day_of_week
        if field.is_simple_range:
            first, last = field.values[0], field.values[-1]
            return f"{WEEKDAY_NAMES[first]} through {WEEKDAY_NAMES[last]}"
        return join_human([WEEKDAY_NAMES[day] for day in field.values])

    def _describe_months(self) -> str:
        field = self.month
        if field.is_simple_range:
            first, last = field.values[0], field.values[-1]
            return f"{MONTH_NAMES[first - 1]} through {MONTH_NAMES[last - 1]}"
        return join_human([MONTH_NAMES[month - 1] for month in field.values])


# --------------------------------------------------------------------------- #
# Parsing
# --------------------------------------------------------------------------- #


def parse_cron(expression: str) -> CronSchedule:
    """Parse a 5-field cron expression into a `CronSchedule`."""
    tokens = expression.split()
    if len(tokens) != 5:
        raise CronParseError(
            f"Expected 5 fields (got {len(tokens)}): {expression!r}"
        )

    minute, hour, day_of_month, month, day_of_week = (
        parse_field(token, spec) for token, spec in zip(tokens, FIELD_ORDER)
    )
    return CronSchedule(minute, hour, day_of_month, month, day_of_week)


def parse_field(token: str, spec: FieldSpec) -> CronField:
    """Parse one field token (which may be a comma-separated list) into values."""
    values: set[int] = set()
    for item in token.split(","):
        values.update(expand_item(item, spec))
    return CronField(raw=token, values=tuple(sorted(values)))


def expand_item(item: str, spec: FieldSpec) -> list[int]:
    """Expand a single list item (`*`, `a`, `a-b`, or any of these `/s`)."""
    range_part, step = split_step(item, spec)
    low, high = parse_range(range_part, spec)
    return list(range(low, high + 1, step))


def split_step(item: str, spec: FieldSpec) -> tuple[str, int]:
    """Split "1-30/5" into its range part "1-30" and step 5."""
    if "/" not in item:
        return item, 1

    range_part, _, step_text = item.partition("/")
    if not step_text.isdigit() or int(step_text) == 0:
        raise CronParseError(
            f"Invalid step {step_text!r} in {spec.name} field item {item!r}"
        )
    return range_part, int(step_text)


def parse_range(range_part: str, spec: FieldSpec) -> tuple[int, int]:
    """Resolve the range part of an item into inclusive (low, high) bounds."""
    if range_part == "*":
        return spec.min_value, spec.max_value

    if "-" in range_part:
        low_text, _, high_text = range_part.partition("-")
        low, high = parse_value(low_text, spec), parse_value(high_text, spec)
        if low > high:
            raise CronParseError(
                f"Range start {low} is after end {high} in {spec.name} field"
            )
        return low, high

    value = parse_value(range_part, spec)
    return value, value


def parse_value(text: str, spec: FieldSpec) -> int:
    """Parse a single number and verify it falls within the field's range."""
    if not re.fullmatch(r"\d+", text):
        raise CronParseError(f"Invalid {spec.name} value: {text!r}")

    value = int(text)
    if not spec.min_value <= value <= spec.max_value:
        raise CronParseError(
            f"{spec.name} value {value} out of range "
            f"[{spec.min_value}, {spec.max_value}]"
        )
    return value


# --------------------------------------------------------------------------- #
# Small English-formatting helpers
# --------------------------------------------------------------------------- #


def _is_on_the_hour(minute: CronField) -> bool:
    """True when the minute field is exactly 0."""
    return minute.is_single_value and minute.values == (0,)


def _describe_clock_time(hour: int, minute: int) -> str:
    """Render a single clock time, e.g. "At 08:30" or "At midnight"."""
    if hour == 0 and minute == 0:
        return "At midnight"
    return f"At {hour:02d}:{minute:02d}"


def join_human(items: list[str]) -> str:
    """Join items with commas and a trailing "and": "a, b, and c"."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + ", and " + items[-1]


def ordinal(number: int) -> str:
    """Return the ordinal form of a number, e.g. 1 -> "1st"."""
    if 10 <= number % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(number % 10, "th")
    return f"{number}{suffix}"


# --------------------------------------------------------------------------- #
# Demonstration
# --------------------------------------------------------------------------- #


if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expression in examples:
        schedule = parse_cron(expression)
        print(f"{expression:<16} -> {schedule.describe()}")
```

## How it's decomposed

The code is split into four layers that each do one thing:

| Layer | Functions | Responsibility |
|-------|-----------|----------------|
| **Specs** | `FieldSpec`, `MINUTE`…`DAY_OF_WEEK` | Declare each field's name and valid range as data, so ranges aren't hardcoded in logic |
| **Parsing** | `parse_cron` → `parse_field` → `expand_item` → `split_step` / `parse_range` / `parse_value` | A single chain that handles `*`, ranges, lists, and steps **once** — no per-field duplication |
| **Structure** | `CronField`, `CronSchedule` | Immutable dataclasses; `CronField` keeps the raw token so the describer can tell wildcards from steps from ranges |
| **Description** | `describe` + `_describe_*` helpers, `join_human`, `ordinal` | English rendering kept entirely separate from parsing |

Key decisions for readability:
- **One field parser, reused 5×.** `parse_cron` just `zip`s tokens with `FIELD_SPECS`; every field flows through the same `parse_field` → `expand_item` pipeline.
- **The grammar is split by structure, not by regex soup.** `split_step` peels off `/s`, `parse_range` handles `*` / `a-b` / `a`, and `parse_value` does the single-number range check. Each is independently testable.
- **Validation lives at the leaf** (`parse_value`, `split_step`) so every error message names the offending field and value.
- **`describe()` reads as prose**: a time clause plus an optional calendar clause, with the common cron idioms ("Every N minutes", "on the hour", "midnight") handled explicitly and an `_describe_irregular_time` fallback for the long tail.

