class CronField:
    name: str
    expression: str
    minimum: int
    maximum: int
    values: FrozenSet[int]

    @property
    def is_wildcard(self) -> bool:
        return self.values == frozenset(range(self.minimum, self.maximum + 1))

    @property
    def single_value(self) -> int | None:
        if len(self.values) == 1:
            return next(iter(self.values))
        return None


@dataclass(frozen=True)
class CronSchedule:
