            return "Every minute"

        if self._runs_every_n_minutes():
            return f"Every {self._step_size(self.minute.expression)} minutes"

        if self._runs_every_n_hours_on_the_hour():
            return f"Every {self._step_size(self.hour.expression)} hours, on the hour"

        time_text = self._describe_time()
        date_parts = self._describe_date_parts()

        if date_parts:
            return f"{time_text} {', '.join(date_parts)}"

        return time_text

    def _runs_every_minute(self) -> bool:
        return (
            self.minute.is_wildcard
            and self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )

    def _runs_every_n_minutes(self) -> bool:
        return (
            self.minute.expression.startswith("*/")
            and self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )

    def _runs_every_n_hours_on_the_hour(self) -> bool:
        return (
            self.minute.single_value == 0
            and self.hour.expression.startswith("*/")
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )

    def _describe_time(self) -> str:
        minute = self.minute.single_value
        hour = self.hour.single_value

        if hour is not None and minute is not None:
            if hour == 0 and minute == 0:
                return "At midnight"
            return f"At {hour:02d}:{minute:02d}"

        if hour is not None and self.minute.is_wildcard:
            return f"Every minute during the {hour:02d}:00 hour"

        if minute is not None and self.hour.is_wildcard:
            return f"At minute {minute} of every hour"

        return "At scheduled times"

    def _describe_date_parts(self) -> list[str]:
