        if not self.day_of_month.is_wildcard:
            parts.append(f"on the {_format_ordinals(self.day_of_month.values)}")

        if not self.month.is_wildcard:
            parts.append(f"in {_format_names(self.month.values, MONTH_NAMES)}")

        if not self.day_of_week.is_wildcard:
            parts.append(f"on {_format_weekdays(self.day_of_week)}")

