def parse_cron_expression(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise ValueError(
            f"Expected 5 cron fields: minute hour day_of_month month day_of_week; "
            f"got {len(parts)} field(s)."
