        minute=parse_field("minute", minute, 0, 59),
        hour=parse_field("hour", hour, 0, 23),
        day_of_month=parse_field("day_of_month", day_of_month, 1, 31),
        month=parse_field("month", month, 1, 12),
        day_of_week=parse_field("day_of_week", day_of_week, 0, 6),
    )


def parse_field(name: str, expression: str, minimum: int, maximum: int) -> CronField:
    if not expression:
        raise ValueError(f"{name} field cannot be empty.")

    values: set[int] = set()

    for item in expression.split(","):
        values.update(_parse_field_item(name, item, minimum, maximum))

    return CronField(
        name=name,
        expression=expression,
        minimum=minimum,
        maximum=maximum,
        values=frozenset(sorted(values)),
    )


def _parse_field_item(name: str, item: str, minimum: int, maximum: int) -> set[int]:
    if not item:
        raise ValueError(f"{name} field contains an empty list item.")

    base, step = _split_step(name, item)
    start, end = _parse_range_base(name, base, minimum, maximum)

    if step < 1:
        raise ValueError(f"{name} step must be at least 1.")

    return set(range(start, end + 1, step))


def _split_step(name: str, item: str) -> tuple[str, int]:
    if "/" not in item:
        return item, 1

    base, raw_step = item.split("/", 1)

    if not base or not raw_step:
        raise ValueError(f"{name} step expression '{item}' is incomplete.")

    return base, _parse_int(name, raw_step)


def _parse_range_base(
    name: str,
    base: str,
    minimum: int,
    maximum: int,
) -> tuple[int, int]:
    if base == "*":
        return minimum, maximum

    if "-" in base:
        raw_start, raw_end = base.split("-", 1)

        if not raw_start or not raw_end:
            raise ValueError(f"{name} range '{base}' is incomplete.")

        start = _parse_int(name, raw_start)
        end = _parse_int(name, raw_end)

        _validate_value(name, start, minimum, maximum)
        _validate_value(name, end, minimum, maximum)

        if start > end:
            raise ValueError(f"{name} range '{base}' starts after it ends.")

        return start, end

    value = _parse_int(name, base)
    _validate_value(name, value, minimum, maximum)
    return value, value


def _parse_int(name: str, raw_value: str) -> int:
    if not raw_value.isdigit():
        raise ValueError(f"{name} value '{raw_value}' is not a valid integer.")

    return int(raw_value)


def _validate_value(name: str, value: int, minimum: int, maximum: int) -> None:
    if value < minimum or value > maximum:
        raise ValueError(
            f"{name} value {value} is out of range; expected {minimum}-{maximum}."
        )


def _format_weekdays(field: CronField) -> str:
    values = sorted(field.values)

    if _is_contiguous(values):
        return f"{WEEKDAY_NAMES[values[0]]} through {WEEKDAY_NAMES[values[-1]]}"

    return _format_names(values, WEEKDAY_NAMES)


def _format_names(values: Iterable[int], names: dict[int, str]) -> str:
    return _join_english([names[value] for value in sorted(values)])


def _format_ordinals(values: Iterable[int]) -> str:
    return _join_english([_ordinal(value) for value in sorted(values)])


def _join_english(items: list[str]) -> str:
    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def _ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


def _is_contiguous(values: list[int]) -> bool:
    return values == list(range(values[0], values[-1] + 1))


